import{_ as e,c as o,o as t,a4 as a}from"./chunks/framework.BmdFiWrL.js";const f=JSON.parse('{"title":"Login FAQ","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/guide/loginq.md","filePath":"en_US/guide/loginq.md","lastUpdated":1780231899000}'),i={name:"en_US/guide/loginq.md"},n=a('<h1 id="login-faq" tabindex="-1">Login FAQ <a class="header-anchor" href="#login-faq" aria-label="Permalink to &quot;Login FAQ&quot;">​</a></h1><p>Since v1, the Dashboard uses local account login and supports binding local accounts to OAuth2 third-party accounts. Legacy GitHub OAuth login issues no longer apply to the current login flow.</p><h2 id="forgot-administrator-password" tabindex="-1">Forgot Administrator Password <a class="header-anchor" href="#forgot-administrator-password" aria-label="Permalink to &quot;Forgot Administrator Password&quot;">​</a></h2><p>See <a href="/en_US/guide/q13.html">Initialize User Password</a>. After resetting it, log in to the admin frontend and change it to a new strong password as soon as possible.</p><h2 id="oauth2-login-failed" tabindex="-1">OAuth2 Login Failed <a class="header-anchor" href="#oauth2-login-failed" aria-label="Permalink to &quot;OAuth2 Login Failed&quot;">​</a></h2><p>Check the following first:</p><ol><li>The <code>oauth2</code> field in the Dashboard configuration uses the new structure. See <a href="/en_US/guide/q14.html">Setting Up OAuth 2.0 Binding</a>.</li><li>The Callback URL on the third-party platform is <code>https://your-dashboard-domain/api/v1/oauth2/callback</code>.</li><li>You have already logged in with a local account and completed OAuth2 binding on the profile page.</li></ol><p>If no binding relationship exists yet, OAuth2 cannot directly log in to a local account.</p><h2 id="login-endpoint-is-frequently-tried-or-incorrectly-blocked" tabindex="-1">Login Endpoint Is Frequently Tried or Incorrectly Blocked <a class="header-anchor" href="#login-endpoint-is-frequently-tried-or-incorrectly-blocked" aria-label="Permalink to &quot;Login Endpoint Is Frequently Tried or Incorrectly Blocked&quot;">​</a></h2><p>v1 introduces a Web Application Firewall to limit login brute force attempts. If the Dashboard is deployed behind a reverse proxy or CDN, configure the <a href="/en_US/guide/q12.html">Frontend Real IP Request Header</a> correctly; otherwise, the Dashboard may misidentify visitor IPs and block incorrectly.</p><p>If an IP has already been blocked by mistake, use an administrator account to remove the corresponding block record under <strong>System Settings → Web Application Firewall</strong>.</p>',11),r=[n];function l(d,s,c,h,u,p){return t(),o("div",null,r)}const _=e(i,[["render",l]]);export{f as __pageData,_ as default};
